import{_ as t,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"80. Union Matters","description":"","frontmatter":{"title":"80. Union Matters","eba":"Nurses and Midwives 2024-2028","topics":["union-matters"]},"headers":[],"relativePath":"ebas/nurses-midwives/union-matters/80-union-matters.md","filePath":"ebas/nurses-midwives/union-matters/80-union-matters.md"}'),r={name:"ebas/nurses-midwives/union-matters/80-union-matters.md"};function s(a,e,p,l,g,h){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_80-union-matters" tabindex="-1">80. Union Matters <a class="header-anchor" href="#_80-union-matters" aria-label="Permalink to &quot;80. Union Matters&quot;">​</a></h1><p><strong>80.1</strong> Access to Employees – General</p><p>The Union will have access to Employees for any process arising under this Agreement.</p><p><strong>80.2</strong> Access to Employees – Electronic communication</p><p>The Employer will ensure that:</p><p><strong>(a)</strong> emails from the Union domain name are not blocked or restricted by or on behalf of the Employer, except in respect of any individual Employee who has made a written request to the Employer to block such emails;</p><p><strong>(b)</strong> emails from Employees to the Union are not blocked or restricted by or on behalf of the Employer;</p><p><strong>(c)</strong> access from health service computers and like devices to Union websites and online information is not blocked, or limited; and</p><p><strong>(d)</strong> where a genuine security concern arises regarding the above, the Employer will immediately notify the Union to enable the security concern to be addressed.</p><p><strong>80.3</strong> Access to Employees – Orientation</p><p><strong>(a)</strong> The Union may attend and address new Employees as part of orientation/induction programs for new Employees (where the orientation/induction may include a person eligible for membership of the Union), provided that any attendance for the purposes of discussions with the Employees meets the right of entry requirements under Part 3-4 of the Act (Entry Requirements). The details of such attendance will be arranged by the Employer in consultation with the Union.</p><p><strong>(b)</strong> An Employer will advise the Union of the date, time and location of orientation/induction programs not less than 14 days prior to the orientation/induction program.</p><p><strong>(c)</strong> Those covered by this Agreement acknowledge the increasing role that technology plays in orientation/induction. An Employer and Union may agree to an alternative means by which the Union can access new Employees including where orientation/induction programs are conducted online or the Union cannot reasonably attend, provided that such access is consistent with the Entry Requirements.</p><p><strong>80.4</strong> Delegates and HSRs</p><p>Note: Additional rights of HSRs are contained in the OHS Act.</p><p><strong>(a)</strong> In this clause 80.4:</p><p><strong>(i)</strong> Representative means a Union Delegate, or a HSR;</p><p><strong>(ii)</strong> Relevant Employee means:</p><p><strong>(A)</strong> In the case of a Union Delegate, members of the Union and any other persons eligible to be members of the Union; and</p><p><strong>(B)</strong> In the case of a HSR, members of the designated work group eligible to be represented by the HSR.</p><p><strong>(iii)</strong> Union Delegate means, for the purposes of this clause, an Employee who presents themselves as a delegate of a Union to their Employer, subject to:</p><p><strong>(A)</strong> the Union&#39;s applicable policies (if any); and</p><p><strong>(B)</strong> the ANMF (in the case of a delegate of the ANMF) informing the Employer in writing of the Employee&#39;s status as a Union Delegate.</p><p><strong>(b)</strong> A Union Delegate is entitled to:</p><p><strong>(i)</strong> represent the industrial interests of Relevant Employees, including in disputes between that person and the Employer; and</p><p><strong>(ii)</strong> reasonable communication with members of the Union, and any other persons eligible to be members of the Union, in relation to their industrial interests. Communication may occur during working hours or work breaks, or before or after work.</p><p><strong>(c)</strong> For the purposes of representing the industrial interests of members of the Union and any other persons eligible to be members of the Union, a Union Delegate is entitled to reasonable access to the workplace of the Employer and any workplace facilities where work of the Employer is being undertaken.</p><p><strong>(d)</strong> A Representative is entitled to reasonable time release from duty to:</p><p><strong>(i)</strong> attend to matters relating to industrial, occupational health and safety or other relevant matters such as assisting with grievance procedures and attending committee meetings;</p><p><strong>(ii)</strong> access reasonable preparation time before meetings with management disciplinary or grievance meetings with a Relevant Employee;</p><p><strong>(iii)</strong> in the case of a Union Delegate:</p><p><strong>(A)</strong> appear as a witness or participate in conciliation or arbitration, before the Commission; and/or</p><p><strong>(B)</strong> present information on the Union at orientation sessions for new Employees.</p><p><strong>(e)</strong> A Representative required to attend management or consultative meetings outside of paid time will be paid to attend.</p><p><strong>(f)</strong> A Representative will be provided with access to facilities such as:</p><p><strong>(i)</strong> telephones;</p><p><strong>(ii)</strong> computers;</p><p><strong>(iii)</strong> emails;</p><p><strong>(iv)</strong> noticeboards;</p><p><strong>(v)</strong> meeting rooms or areas to hold discussions that are fit for purpose, private and accessible by the workplace delegate and eligible employees;</p><p><strong>(vi)</strong> Wi-Fi;</p><p><strong>(vii)</strong> a lockable filing cabinet or other secure document storage area; and</p><p><strong>(viii)</strong> office facilities and equipment including printers, scanners and photocopiers</p><p>in a manner that does not adversely affect service delivery and work requirements of the Employer. In the case of a HSR, facilities will include other facilities as necessary to enable them to perform their functions as prescribed under the OHS Act.</p><p><strong>(g)</strong> Except as otherwise required by law, the Employer will not:</p><p><strong>(i)</strong> unreasonably fail or refuse to deal with a Union Delegate; or</p><p><strong>(ii)</strong> knowingly or recklessly make a false or misleading representation to a Union Delegate; or</p><p><strong>(iii)</strong> unreasonably hinder, obstruct or prevent a Union Delegate from exercising any of their rights;</p><p>insofar as the Union Delegate is acting in their capacity as a Representative.</p><p><strong>80.5</strong> Noticeboard</p><p><strong>(a)</strong> A noticeboard for the Union&#39;s use will be readily accessible in each ward/unit/work area or nearest staff room where persons eligible to be members of the Union are employed.</p><p><strong>(b)</strong> The Union and members covered by this Agreement will, during the life of this Agreement, consult over the development of an electronic noticeboard managed by the Union.</p><p><strong>80.6</strong> Meeting Space</p><p>In the absence of agreement on a location for the holding of Union meetings, the room where one or more of the Employees who may participate in the meeting ordinarily take meal or other breaks will be the meeting room for the purpose of Union meetings. Nothing in this clause is intended to override the operation of the Act.</p><p><strong>80.7</strong> Secondment to the Union</p><p>The Employer will, on application, grant leave without pay to an Employee for the purpose of secondment or other arrangement to work for the Union subject to the Employer&#39;s reasonable operational requirements.</p><p><strong>80.8</strong> Employees holding Union official positions</p><p>The Employer will, on application by the Union, grant leave without loss of pay to an Employee for the purpose of fulfilling their duties as an official of the Council or Executive body of the Union. For a member of the ANMF Council, this currently involves 11 half day meetings per year (plus travel time). For Executive Council members, this involves an additional 11 half day meetings (plus travel time). For a member of the HSU Branch Committee of Management, this currently involves 11 full day meetings per year.</p><p><strong>80.9</strong> Union Delegate Training</p><p>Note: Where a Union Delegate is also appointed a HSR under the OHS Act, they may be entitled to additional training in accordance with the OHS Act.</p><p><strong>(a)</strong> Subject to the conditions in this clause 80.9, Employees selected by the Union to attend training courses on industrial relations and/or health and safety will be entitled to a maximum of five days&#39; paid leave per calendar year per Employee.</p><p><strong>(b)</strong> Leave in excess of five days and up to ten days may be granted in a calendar year subject to the total leave being granted in that year and in the subsequent year not exceeding ten days.</p><p><strong>(c)</strong> The granting of leave will be subject to the Employer&#39;s operational requirements. The granting of leave will not be unreasonably withheld.</p><p><strong>(d)</strong> Leave under this clause is granted on the following conditions:</p><p><strong>(i)</strong> applications are accompanied by a statement from the Union advising that it has nominated the Employee or supports the application;</p><p><strong>(ii)</strong> the training is conducted by the Union, an association of Unions or accredited training provider; and</p><p><strong>(iii)</strong> the application is made as early as practicable and not less than two (2) weeks before the training.</p><p><strong>(e)</strong> The Employee will be paid their &#39;ordinary pay&#39; (as defined at 57 (Annual Leave)) for normal rostered hours (set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>), but excluding shift work, overtime and other allowances.</p><p><strong>(f)</strong> Leave in accordance with this clause may include necessary travelling time in normal hours immediately before or after the course.</p><p><strong>(g)</strong> Leave granted under this clause will count as service for all purposes of this Agreement.</p><p><strong>(h)</strong> Expenses associated with attendance at training courses, including fares, accommodation and meal costs are not the responsibility of the Employer.</p><p><strong>80.10</strong> Workplace Implementation Committees</p><p><strong>(a)</strong> A local WIC will continue or, if there is not currently a WIC in operation, be established at each Employer for the purposes of:</p><p><strong>(i)</strong> agreement implementation;</p><p><strong>(ii)</strong> ongoing monitoring and assessment of the implementation of this Agreement; and</p><p><strong>(iii)</strong> dealing with any local disputes that may arise, without limiting the Dispute Resolution Procedure in this Agreement.</p><p><strong>(b)</strong> Having regard to their size and location, a WIC may be appropriate at each facility/Campus.</p><p><strong>(c)</strong> The WIC will, where practicable, comprise equal numbers of representatives of the Employer and the Unions.</p><p><strong>(d)</strong> The WIC will meet as required to satisfy the purpose described at (a) above and, in the event it ceases meeting, will be reconvened at the request of the Employer or Union covered by this Agreement.</p><p><strong>(e)</strong> Representatives of the ANMF may include nominees of the ANMF employed by the Employer, in which case the Employer will provide paid time for those nominees to participate.</p><p><strong>(f)</strong> The Employer will make available to the WIC information reasonably necessary to fulfil the objectives in (a) above.</p><p><strong>(g)</strong> Priority items for consideration by the WIC will include:</p><p><strong>(i)</strong> Carparking with respect to the safety of Employees, including getting to and from carparking;</p><p><strong>(ii)</strong> Operation of the supplementary roster (see <a href="/eba/ebas/nurses-midwives/hours-of-work/46-supplementary-roster-and-additional-shifts.html">clause 46</a>);</p><p><strong>(iii)</strong> Public holiday rostering requirements (see <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45.9</a>);</p><p><strong>(iv)</strong> Allocation of paid time for Employees with portfolio or administrative responsibilities (see <a href="/eba/ebas/nurses-midwives/hours-of-work/45A-portfolio-work-in-paid-time.html">clause 45A.2</a>); and</p><p><strong>(v)</strong> Night shift arrangements.</p><p><strong>(h)</strong> Other activities undertaken by the WIC include:</p><p><strong>(i)</strong> Gender equity activities, including Audit and Action Plan (standing item) (see <a href="/eba/ebas/nurses-midwives/preliminary/10A-gender-based-discrimination.html">clause 10A.5</a>);</p><p><strong>(ii)</strong> Engagement with respect to climate change and sustainability activities (where there is not an alternative local mechanism) (see <a href="/eba/ebas/nurses-midwives/consultation-disputes/16B-climate-change-mitigation-and-sustainability.html">clause 16B.2</a>);</p><p><strong>(iii)</strong> Working cooperatively to address instances of contact inconsistent with the ‘Right to Disconnect’ clause (see <a href="/eba/ebas/nurses-midwives/hours-of-work/52-right-to-disconnect.html">clause 52</a>);</p><p><strong>(iv)</strong> Discuss the Employer’s activities to promote secure employment (see subclause 87.2(e));</p><p><strong>(v)</strong> Receiving reports on the following:</p><p><strong>(A)</strong> Unresolved Employee requests to rectify underpayments (see <a href="/eba/ebas/nurses-midwives/wages/26-payment-of-wages-employee-records-and-related-matters.html">clause 26.5</a>);</p><p><strong>(B)</strong> The progress of transition to permanent night shift arrangements (see subclause 42A.3(e));</p><p><strong>(C)</strong> Evaluation of permanent night shift to ensure no unintended consequences (see <a href="/eba/ebas/nurses-midwives/hours-of-work/42A-permanent-night-shift.html">clause 42A.7</a>);</p><p><strong>(D)</strong> Evaluation of other night shift arrangements to ensure no unintended consequences (see <a href="/eba/ebas/nurses-midwives/hours-of-work/42B-night-shift-rostering-principles-other-than-permanent-night.html">clause 42B.4</a>);</p><p><strong>(E)</strong> The positions that are not rostered (see subclause 45.10(c));</p><p><strong>(F)</strong> The results of a review of arrangements for contacting Employee’s out of hours to determine availability (see subclause 52.3(b)); and</p><p><strong>(G)</strong> Manual handling where those reports are not provided to an OHS Committee (see subclause 99.8(c)).</p><p><strong>80.11</strong> Central Implementation Committee</p><p><strong>(a)</strong> A Central Implementation Committee (CIC) will be established comprising representatives of the ANMF, VHIA and the Department of Health to oversee and, as far as practicable, resolve disputes regarding:</p><p><strong>(i)</strong> agreement implementation; and</p><p><strong>(ii)</strong> this Agreement;</p><p>that cannot be resolved at the local level, without limiting the Dispute Resolution Procedure in this Agreement.</p><p><strong>(b)</strong> The CIC will continue to operate throughout the life of the Agreement.</p><p><strong>(c)</strong> Each Employer will make available to the CIC information reasonably necessary to fulfil the objectives in subclauses 80.11(a)(i) and (ii) above.</p><p><strong>80.12</strong> The parties agree the following matters will form part of the work of the CIC during the life of the Agreement:</p><p><strong>(a)</strong> implementation of the Agreement;</p><p><strong>(b)</strong> implementation of a best practice guide to address emerging equity issues arising from flexible working arrangements, sexual harassment and discrimination;</p><p><strong>(c)</strong> any legislative requirement to undertake gender equity activities;</p><p><strong>(d)</strong> consolidation of major agreement provisions to reduce complexity and inefficiencies within the public health system;</p><p><strong>(e)</strong> aged care staffing arrangements;</p><p><strong>(f)</strong> remote location incentivisation schemes;</p><p><strong>(g)</strong> review of template change impact statements; and</p><p><strong>(h)</strong> development and implementation of the Registered Enrolled Nursing Students (RENS) employment model.</p><p>Plain language terms: union rep, delegate, union representative, right of entry.</p>',117)])])}const d=t(r,[["render",s]]);export{c as __pageData,d as default};
